-- Split into smaller files to keep D1 migration statements manageable.

UPDATE core_vocabulary SET word = 'do', meaning_zh = '做；完成；用于构成疑问或否定', definition_en = 'to perform an action, task, or activity', primary_part_of_speech = 'verb', phonetic_us = '/du, də/', phonetic_uk = '/duː, də/', updated_at = CURRENT_TIMESTAMP WHERE id = 'do';
UPDATE vocabulary_pronunciations SET phonetic = CASE accent WHEN 'us' THEN '/du, də/' WHEN 'uk' THEN '/duː, də/' ELSE phonetic END, phonetic_source = 'manual-curation', updated_at = CURRENT_TIMESTAMP WHERE vocabulary_id = 'do' AND accent IN ('us', 'uk');

